import React, { useState, useEffect } from "react";
import api from "../api/api";
import Pagination from "../components/Pagination";
import TicketVenta from "../components/TicketVenta"; // Reutilizamos tu ticket
import { FaHistory, FaEye, FaCalendarAlt, FaUser, FaDollarSign } from "react-icons/fa";

export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [ticketSeleccionado, setTicketSeleccionado] = useState(null);

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const ventasPorPagina = 8;

  useEffect(() => {
    obtenerVentas();
  }, []);

  const obtenerVentas = async () => {
    try {
      setLoading(true);
      const res = await api.get("/ventas");
      setVentas(res.data || []);
    } catch (error) {
      console.error("❌ Error al obtener historial:", error);
    } finally {
      setLoading(false);
    }
  };

  // Lógica de Paginación
  const inicio = (paginaActual - 1) * ventasPorPagina;
  const ventasPaginadas = ventas.slice(inicio, inicio + ventasPorPagina);

  if (loading) return (
    <div className="text-center mt-5">
      <div className="spinner-border text-primary"></div>
      <p className="mt-2">Cargando historial de ventas...</p>
    </div>
  );

  return (
    <div className="container-fluid p-4">
      <div className="card border-0 shadow-sm p-4 mb-4 bg-white rounded-4">
        <h3 className="fw-bold m-0 text-dark">
          <FaHistory className="me-2 text-primary" /> Historial de Ventas
        </h3>
      </div>

      <div className="table-responsive shadow-sm rounded-4 overflow-hidden bg-white">
        <table className="table table-hover align-middle mb-0">
          <thead className="table-dark text-center">
            <tr>
              <th><FaCalendarAlt className="me-1"/> Fecha</th>
              <th># Ticket</th>
              <th><FaUser className="me-1"/> Cliente</th>
              <th><FaDollarSign className="me-1"/> Total</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody className="text-center">
            {ventasPaginadas.length === 0 ? (
              <tr>
                <td colSpan="5" className="py-5 text-muted">No se han registrado ventas aún.</td>
              </tr>
            ) : (
              ventasPaginadas.map((v) => (
                <tr key={v._id}>
                  <td>
                    {v.createdAt 
                      ? new Date(v.createdAt).toLocaleDateString() 
                      : "S/Fecha"}
                  </td>
                  {/* ✅ PROTECCIÓN: .slice() solo si el _id existe */}
                  <td className="fw-bold text-primary">
                    {v._id ? `#${v._id.slice(-6).toUpperCase()}` : "------"}
                  </td>
                  <td>
                    {/* Verificamos si existe cliente_id o nombre directo */}
                    {v.cliente_id?.nombre || v.nombre_cliente || "Consumidor Final"}
                  </td>
                  <td className="fw-bold text-success">
                    ${Number(v.total || 0).toFixed(2)}
                  </td>
                  <td>
                    <button 
                      className="btn btn-sm btn-outline-primary fw-bold rounded-pill"
                      onClick={() => setTicketSeleccionado(v)}
                    >
                      <FaEye className="me-1" /> Re-imprimir
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <Pagination 
        totalItems={ventas.length}
        itemsPerPage={ventasPorPagina}
        currentPage={paginaActual}
        onPageChange={setPaginaActual}
      />

      {/* ✅ Modal para ver el ticket nuevamente */}
      {ticketSeleccionado && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.7)", zIndex: 1050 }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 bg-transparent">
              {/* Le pasamos la venta seleccionada al componente TicketVenta que ya tienes corregido */}
              <TicketVenta 
                ticket={ticketSeleccionado} 
                setTicket={setTicketSeleccionado} 
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
